     * Extracts a metric from XML content using an XPath expression.
     * 
     * @param xmlContent The XML string to parse.
     * @param xpathExpression The XPath expression to evaluate.
     * @return The extracted value as a String.
     * @throws RuntimeException if parsing or evaluation fails.
     */
    public String extractMetric(String xmlContent, String xpathExpression) {
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            throw new IllegalArgumentException("XML content cannot be null or empty");
